# novel.py ? ??????# ?? + ???? + ???? + ???? + ???? + ????import osimport reimport timeimport jsonimport threadingfrom datetime import datetimefrom core import (    llm_invoke, llm_invoke_ada, read_file, write_file,    append_file, ensure_dir, count_words, get_output_dir)from prompts import (    SETTING_GENERATION, DIRECTORY_GENERATION,    CHAPTER_GENERATION, SUMMARY_UPDATE,    CONSISTENCY_CHECK_PROMPT, EXTRACT_CHARACTERS_PROMPT)from deslop import rule_based_deslopCHECKPOINT_FILE = "checkpoint.json"# ???????????????????????????????????????????????????????????# ??# ???????????????????????????????????????????????????????????def prepare_book_dir(topic: str) -> str:    dir_name = re.sub(r'[\\/:*?"<>|]', '', topic)[:30].strip()    if not dir_name:        dir_name = f"novel_{int(time.time())}"    book_dir = os.path.join(get_output_dir(), dir_name)    ensure_dir(book_dir)    ensure_dir(os.path.join(book_dir, "??"))    return book_dir# ???????????????????????????????????????????????????????????# ?? 1?????# ???????????????????????????????????????????????????????????def save_checkpoint(book_dir: str, chapter_num: int, summary: str,                     total_chapters: int = 0, topic: str = "",                     genre: str = "", target_words: int = 3000):    cp = {        "chapter_completed": chapter_num,        "total_chapters": total_chapters,        "summary": summary,        "topic": topic,        "genre": genre,        "target_words": target_words,        "last_update": datetime.now().strftime("%Y-%m-%d %H:%M:%S")    }    # ????????? tmp???? rename    tmp_path = os.path.join(book_dir, CHECKPOINT_FILE + ".tmp")    write_file(tmp_path, json.dumps(cp, ensure_ascii=False, indent=2))    target = os.path.join(book_dir, CHECKPOINT_FILE)    if os.path.exists(target):        os.remove(target)    os.rename(tmp_path, target)def load_checkpoint(book_dir: str):    path = os.path.join(book_dir, CHECKPOINT_FILE)    if not os.path.exists(path):        return None    try:        return json.loads(read_file(path))    except Exception:        return None# ???????????????????????????????????????????????????????????# Step 1: ????# ???????????????????????????????????????????????????????????def generate_setting(topic: str, genre: str, num_chapters: int,                     book_dir: str, log_callback=None) -> str:    v1 = max(1, num_chapters // 3)    v2 = max(1, num_chapters * 2 // 3)    prompt = SETTING_GENERATION.format(        topic=topic, genre=genre, num_chapters=num_chapters,        v1=v1, v1p1=v1 + 1, v2=v2, v2p1=v2 + 1)    if log_callback:        log_callback("?????????...")    result = llm_invoke_ada(prompt,        system_msg="???????????????????????")    write_file(os.path.join(book_dir, "??.md"), result)    if log_callback:        log_callback(f"???? ({count_words(result)} ?)")    return result# ???????????????????????????????????????????????????????????# Step 2: ????# ???????????????????????????????????????????????????????????def generate_directory(novel_setting: str, num_chapters: int,                       book_dir: str, log_callback=None) -> list:    v1 = max(1, num_chapters // 3)    v2 = max(1, num_chapters * 2 // 3)    prompt = DIRECTORY_GENERATION.format(        num_chapters=num_chapters, novel_setting=novel_setting,        v1=v1, v2=v2)    if log_callback:        log_callback("????????...")    result = llm_invoke_ada(prompt,        system_msg="??????????????????????????")    write_file(os.path.join(book_dir, "??.md"), result)    chapters = _parse_directory(result, num_chapters)    if log_callback:        log_callback(f"?????? ({len(chapters)} ?)")    return chapters# ???????????????????????????????????????????????????????????# Step 3: ????# ???????????????????????????????????????????????????????????def generate_chapter(chapter_num: int, chapter_title: str,                     novel_setting: str, directory_text: str,                     summary: str, target_words: int,                     book_dir: str, log_callback=None,                     stream_callback=None, stop_flag=None) -> dict:    chapter_dir = os.path.join(book_dir, "??")    ensure_dir(chapter_dir)    # ????????? 500 ??    prev_ending = ""    if chapter_num > 1:        prev_files = [f for f in os.listdir(chapter_dir)                      if f.startswith(f"??{chapter_num-1:03d}??")]        if prev_files:            prev_text = read_file(os.path.join(chapter_dir, prev_files[0]))            if prev_text:                prev_ending = prev_text[-500:]    # ??????????    char_ctx = ""    char_path = os.path.join(book_dir, "???????.md")    if os.path.exists(char_path):        char_text = read_file(char_path)        if char_text:            char_ctx = char_text[-2000:]    # ????????    rhythm_ctx = ""    rhythm_path = os.path.join(book_dir, "?????.md")    if os.path.exists(rhythm_path):        rhythm_text = read_file(rhythm_path)        if rhythm_text:            for line in rhythm_text.split("\n"):                if f"??{chapter_num}??" in line:                    rhythm_ctx = line                    break    prompt = CHAPTER_GENERATION.format(        chapter_num=chapter_num, novel_setting=novel_setting,        directory=directory_text, summary_text=summary,        chapter_title=chapter_title, chapter_desc="",        target_words=target_words,        prev_chapter_ending=prev_ending,        character_context=char_ctx,        rhythm_context=rhythm_ctx)    if stream_callback:        collected = []        content = llm_invoke(prompt,            system_msg="?????????????????????????????",            stream_callback=lambda c: (collected.append(c), stream_callback(c)) and None,            stop_flag=stop_flag)        if collected:            content = "".join(collected)    else:        if log_callback:            log_callback("  ???...")        content = llm_invoke_ada(prompt)    if not content or content.startswith("[??]"):        if log_callback:            log_callback(f"  \u2717 ????: {content}")        return {"content": "", "path": "", "words": 0, "success": False}    cleaned, _ = rule_based_deslop(content)    # ???? + ?????    validation = validate_chapter(cleaned, chapter_num, target_words, book_dir)    if not validation["pass"]:        if "????????" in str(validation["issues"]):            hooks = [                "\n\n??????????????????",                "\n\n?????????????????",                "\n\n???????????????????",                "\n\n????????????",            ]            import random            cleaned += random.choice(hooks)        if log_callback and validation["issues"]:            joined_issues = "; ".join(validation["issues"])            log_callback(f"  ?? ????: {joined_issues}")    ch_file = os.path.join(chapter_dir, f"?{chapter_num:03d}?_{chapter_title}.md")    write_file(ch_file, cleaned)    wc = count_words(cleaned)    if log_callback:        log_callback(f"  ? {wc} ?")    return {"content": cleaned, "path": ch_file, "words": wc, "success": True}# ???????????????????????????????????????????????????????????# Step 3b: ??????# ???????????????????????????????????????????????????????????def update_summary(chapter_num: int, chapter_title: str,                   chapter_content: str, current_summary: str,                   book_dir: str, log_callback=None) -> str:    prompt = SUMMARY_UPDATE.format(        summary_text=current_summary, chapter_num=chapter_num,        chapter_title=chapter_title, chapter_content=chapter_content[:2000])    new_summary = llm_invoke_ada(prompt)    write_file(os.path.join(book_dir, "????.txt"), new_summary)    # ??????????? 2500 ?????????    if count_words(new_summary) > 2500:        new_summary = compress_summary(new_summary, book_dir, log_callback)    return new_summary# ???????????????????????????????????????????????????????????# ?? 7??????? 30 ??# Compress summary when it gets too longdef compress_summary(summary, book_dir, log_callback=None):    if count_words(summary) <= 2500:        return summary    prompt = """?????????????800????""" +        """?????????????????????????????""" +        """???????????????????????""" + summary    compressed = llm_invoke_ada(prompt, system_msg="??????????")    if compressed and not compressed.startswith("[??]"):        write_file(os.path.join(book_dir, "????.txt"), compressed)        if log_callback:            log_callback("  ?????")        return compressed    return summarydef check_continuity(prev_chapter_end, curr_chapter_start):    if not prev_chapter_end or not curr_chapter_start:        return {"score": 8, "pass": True, "feedback": "no context"}    prompt = """??????????????????????????""" +        """????????""" + prev_chapter_end + """""" +        """?????????""" + curr_chapter_start + """""" +        """??????????????????????????????????????""" +        """????????????:???? (1-10)??????:??????????:??????"""    result = llm_invoke_ada(prompt)    score = 7    import re as _re    m = _re.search(r"????[??:]\s*(\d+)", result)    if m:        score = int(m.group(1))    return {"score": score, "pass": score >= 6, "feedback": result}# ???????????????????????????????????????????????????????????_auto_save_timer = Nonedef auto_save(book_dir: str, novel_setting: str, chapters: list, summary: str):    """? 30 ??????????? autosave/ ??"""    save_dir = os.path.join(book_dir, "autosave")    ensure_dir(save_dir)    ch_dir = os.path.join(book_dir, "??")    if os.path.exists(ch_dir):        for fname in os.listdir(ch_dir):            if fname.endswith(".md"):                src = os.path.join(ch_dir, fname)                dst = os.path.join(save_dir, fname)                now = time.time()                # ???? 5 ??????????????                if now - os.path.getmtime(src) < 5:                    continue                if not os.path.exists(dst) or os.path.getmtime(src) > os.path.getmtime(dst):                    write_file(dst, read_file(src))    global _auto_save_timer    _auto_save_timer = threading.Timer(30.0, auto_save,        args=(book_dir, novel_setting, chapters, summary))    _auto_save_timer.daemon = True    _auto_save_timer.start()def stop_auto_save():    global _auto_save_timer    if _auto_save_timer:        _auto_save_timer.cancel()        _auto_save_timer = None# ???????????????????????????????????????????????????????????# ?? 8?????# ???????????????????????????????????????????????????????????def rewrite_chapter(chapter_num: int, reason: str, book_dir: str,                    novel_setting: str, directory_text: str,                    target_words: int, log_callback=None) -> dict:    """??????"""    reason_map = {        "short": "???????????????????????",        "water": "??????????????????????",        "off_outline": "????????????????????",        "change_style": "?????????????????",    }    extra_instruction = reason_map.get(reason, "?????????????")    ch_dir = os.path.join(book_dir, "??")    chapters_path = os.path.join(book_dir, "??.md")    dir_text = read_file(chapters_path) or directory_text    summary = read_file(os.path.join(book_dir, "????.txt"))    # ???????    old_path = None    for fname in os.listdir(ch_dir):        if fname.startswith(f"?{chapter_num:03d}?"):            old_path = os.path.join(ch_dir, fname)            break    if old_path:        # ?????? v2        base, ext = os.path.splitext(old_path)        os.rename(old_path, f"{base}_v2{ext}")    prompt = CHAPTER_GENERATION.format(        chapter_num=chapter_num,        novel_setting=novel_setting,        directory=dir_text,        summary_text=summary,        chapter_title=f"?{chapter_num}?????",        chapter_desc=extra_instruction,        target_words=target_words)    if log_callback:        log_callback(f"?????{chapter_num}????: {reason}?...")    content = llm_invoke_ada(prompt)    if not content or content.startswith("[??]"):        return {"content": "", "path": "", "words": 0, "success": False}    cleaned, _ = rule_based_deslop(content)    # ??????    if old_path:        title = os.path.basename(old_path).replace(f"?{chapter_num:03d}?_", "").replace(".md", "")    else:        title = f"?{chapter_num}?"    ch_file = os.path.join(ch_dir, f"?{chapter_num:03d}?_{title}.md")    write_file(ch_file, cleaned)    wc = count_words(cleaned)    if log_callback:        log_callback(f"  ????: {wc} ?")    return {"content": cleaned, "path": ch_file, "words": wc, "success": True}# ???????????????????????????????????????????????????????????# ?? 9???????# ???????????????????????????????????????????????????????????CHARACTER_ARCHIVE_FILE = "????.md"def init_character_archive(book_dir: str, novel_setting: str = ""):    """????????"""    content = "# ????\n\n"    if novel_setting:        content += "## ??????????\n\n"        content += "????????????????????\n\n"    write_file(os.path.join(book_dir, CHARACTER_ARCHIVE_FILE), content)def update_character_archive(chapter_content: str, chapter_num: int, book_dir: str,                              log_callback=None):    """???????????????"""    archive_path = os.path.join(book_dir, CHARACTER_ARCHIVE_FILE)    existing = read_file(archive_path)    if not existing:        init_character_archive(book_dir)    prompt = EXTRACT_CHARACTERS_PROMPT.format(        existing_archive=existing[-3000:] if len(existing) > 3000 else existing,        chapter_text=chapter_content[:4000],        chapter_num=chapter_num    )    result = llm_invoke_ada(prompt,        system_msg="?????????????????????????????")    if result and not result.startswith("[??]"):        append_file(os.path.join(book_dir, CHARACTER_ARCHIVE_FILE),                    f"\n\n--- ?{chapter_num}??? ---\n" + result)    if log_callback:        log_callback(f"  ???????")def check_character_consistency(book_dir: str) -> str:    """??????????"""    archive = read_file(os.path.join(book_dir, CHARACTER_ARCHIVE_FILE))    if not archive:        return "???????"    prompt = CONSISTENCY_CHECK_PROMPT + "\n\n?????\n" + archive[:6000]    result = llm_invoke_ada(prompt,        system_msg="??????????????????")    return result# ???????????????????????????????????????????????????????????# ????# ???????????????????????????????????????????????????????????def generate_novel(config: dict = None,                   log_callback=None,                   stream_callback=None,                   stop_flag=None,                   progress_callback=None,                   custom_outline_path: str = None) -> dict:    from core import load_config    cfg = load_config()    if config:        cfg["novel"].update(config.get("novel", {}))        if "output_dir" in config:            cfg["output_dir"] = config["output_dir"]        if "use_local" in config:            cfg["use_local"] = config["use_local"]    topic = cfg["novel"]["topic"]    genre = cfg["novel"]["genre"]    num_chapters = cfg["novel"]["num_chapters"]    target_words = cfg["novel"]["words_per_chapter"]    if not topic:        return {"error": "?????????topic?"}    book_dir = prepare_book_dir(topic)    start_time = time.time()    if log_callback:        log_callback(f"[??] {topic}")        log_callback(f"   ??: {genre} | {num_chapters}\u7ae0 \u00d7 {target_words}\u5b57")        log_callback(f"   ??: {book_dir}\n")    if progress_callback:        progress_callback("step_start", {"step": "????", "total": num_chapters, "desc": topic})    # ??? Step 1 ?????????????????????????    novel_setting = generate_setting(topic, genre, num_chapters, book_dir, log_callback)    if not novel_setting or (stop_flag and stop_flag.is_set()):        return {"status": "\u5df2\u505c\u6b62", "book_dir": book_dir}    if progress_callback:        progress_callback("step_done", {"step": "????", "result": f"{count_words(novel_setting)} ?"})        progress_callback("step_start", {"step": "????", "total": num_chapters, "desc": ""})    # ??? ??? + ??? ????????????????    try:        from planner import plan_volumes, build_rhythm_table        volumes = plan_volumes(novel_setting, num_chapters, book_dir, log_callback)        rhythm = build_rhythm_table(volumes, num_chapters, book_dir, log_callback)    except ImportError:        if log_callback:            log_callback("  [!] planner???????????")    except Exception as e:        if log_callback:            log_callback(f"  [!] ?????: {e}")    # ??? Step 2: ????????? AI ??? ????????    if custom_outline_path and os.path.exists(custom_outline_path):        # ?????????        if log_callback:            log_callback(f"  ???????: {custom_outline_path}")        dir_text = read_file(custom_outline_path)        chapters = _parse_directory(dir_text, num_chapters)        if not chapters:            if log_callback:                log_callback("  [!] ????????????? AI ??")            chapters = generate_directory(novel_setting, num_chapters, book_dir, log_callback)        else:            # ?????.md            write_file(os.path.join(book_dir, "??.md"), dir_text)            if log_callback:                log_callback(f"  ????????? ({len(chapters)} ?)")    else:        chapters = generate_directory(novel_setting, num_chapters, book_dir, log_callback)        if not chapters or (stop_flag and stop_flag.is_set()):        return {"status": "\u5df2\u505c\u6b62", "book_dir": book_dir}    dir_lines = "\n".join([f"\u7b2c{c['num']:03d}\u7ae0: {c['title']}" for c in chapters])    directory_text = read_file(os.path.join(book_dir, "\u76ee\u5f55.md")) or dir_lines    # ???????    init_character_archive(book_dir, novel_setting)    # ??? Step 3 ?????????????????????????    if log_callback:        log_callback(f"\n\u5f00\u59cb\u9010\u7ae0\u751f\u6210 ({num_chapters} \u7ae0)...")    # ????    cp = load_checkpoint(book_dir)    start_from = 0    summary = f"{topic}?{genre}??{num_chapters}??\n"    if cp:        start_from = cp.get("chapter_completed", 0)        summary = cp.get("summary", summary)        if log_callback and start_from > 0:            log_callback(f"  ????????? {start_from} ???? {start_from + 1} ???")    total_generated = 0    chapters_done = start_from    # ??????    pending = []    for ch in chapters:        if ch['num'] <= start_from:            p = os.path.join(book_dir, "??", f"\u7b2c{ch['num']:03d}\u7ae0_{ch['title']}.md")            if os.path.exists(p):                total_generated += count_words(read_file(p))            continue        pending.append(ch)    # ??????    auto_save(book_dir, novel_setting, chapters, summary)    # ??????????????? fallback ???????    try:        _vector_ctx = VectorContext()    except Exception:        _vector_ctx = None    # ????????? 3 ???????????????????    from concurrent.futures import ThreadPoolExecutor, as_completed    def _submit_chapter(ch, current_summary):        """????????"""        route = _route_model('chapter', cfg)        if route.get('use_local') != cfg.get('use_local', False):            cfg['use_local'] = route['use_local']        return generate_chapter(            ch['num'], ch['title'],            novel_setting, directory_text, current_summary,            target_words, book_dir, log_callback=None,            stream_callback=None, stop_flag=stop_flag)    BATCH_SIZE = 3    for batch_start in range(0, len(pending), BATCH_SIZE):        if stop_flag and stop_flag.is_set():            break        batch = pending[batch_start:batch_start + BATCH_SIZE]        batch_summary = read_file(os.path.join(book_dir, "????.txt")) or summary        # ?????????        if _vector_ctx and chapters_done > start_from:            for ch in batch:                query = ch.get('title', '') + ' ' + ch.get('desc', '')                if query.strip():                    retrieved = _vector_ctx.search(query, n=min(3, chapters_done))                    if retrieved:                        batch_summary = f"{batch_summary}\n\n## ??????\n{retrieved}"        if log_callback:            log_callback(f"[?? {batch_start // BATCH_SIZE + 1}] {len(batch)} ?????...")        # ????        batch_results = {}  # ch_num -> result        with ThreadPoolExecutor(max_workers=3) as executor:            futures = {executor.submit(_submit_chapter, ch, batch_summary): ch for ch in batch}            for future in as_completed(futures):                if stop_flag and stop_flag.is_set():                    executor.shutdown(wait=False, cancel_futures=True)                    break                ch = futures[future]                try:                    result = future.result()                except Exception as e:                    if log_callback:                        log_callback(f"  ? ?{ch['num']}???: {e}")                    continue                # ??+???????????? root.after?                if log_callback:                    log_callback(f"[{ch['num']}/{num_chapters}] {ch['title']} {'?' + str(result['words']) + '?' if result['success'] else '??'}")                if progress_callback:                    progress_callback("chapter_start", {                        "chapter_num": ch['num'], "title": ch['title'], "total": num_chapters})                if not result["success"]:                    continue                chapters_done += 1                total_generated += result["words"]                batch_results[ch['num']] = result                if progress_callback:                    progress_callback("chapter_done", {                        "chapter_num": ch['num'], "title": ch['title'],                        "words": result['words'], "path": result.get('path', ''),                        "elapsed": round(time.time() - start_time, 1),                        "total_words": total_generated})                if stream_callback:                    stream_callback(f"?{ch['num']}???: {result['words']}?\n")                # ??? checkpoint???????????????                save_checkpoint(book_dir, chapters_done, batch_summary)        # ???????????? + ????????????        if not stop_flag or not stop_flag.is_set():            for ch in sorted(batch, key=lambda x: x['num']):                result = batch_results.get(ch['num'])                if not result:                    continue                # ??????                current_summ = read_file(os.path.join(book_dir, "????.txt")) or summary                new_summary = update_summary(                    ch['num'], ch['title'], result['content'],                    current_summ, book_dir, log_callback=log_callback)                # ??????                update_character_archive(                    result['content'], ch['num'], book_dir,                    log_callback=log_callback)                # ????                if _vector_ctx:                    _vector_ctx.add_chapter(ch['num'], ch['title'], result["content"])                # ??????                save_checkpoint(book_dir, chapters_done, new_summary or current_summ)    stop_auto_save()    # ??? ?? ???????????????????????????    elapsed = time.time() - start_time    res = {        "status": "??" if chapters_done == num_chapters else "????",        "book_dir": book_dir, "topic": topic, "genre": genre,        "chapters_planned": num_chapters, "chapters_done": chapters_done,        "total_words": total_generated,        "elapsed_seconds": round(elapsed, 1),        "words_per_minute": round(total_generated / (elapsed / 60), 0) if elapsed > 0 else 0    }    report = f"""# ?????{topic}- ???{res['status']}- ???{genre}- ?????{num_chapters}- ?????{chapters_done}- ????{total_generated:,}- ???{elapsed:.0f} ?- ?????{res['words_per_minute']:.0f} ?/??- ?????{book_dir}"""    write_file(os.path.join(book_dir, "????.md"), report)    # ??????? checkpoint    if chapters_done == num_chapters:        cp_path = os.path.join(book_dir, CHECKPOINT_FILE)        if os.path.exists(cp_path):            os.remove(cp_path)    if log_callback:        log_callback(f"\n{'='*50}")        log_callback(f"\u2705 ?? {chapters_done}/{num_chapters} ? | {total_generated:,} ? | {elapsed:.0f}s")        log_callback(f"[??] {book_dir}")        log_callback(f"{'='*50}")    # ????    try:        from export import export_all        export_all(book_dir, log_callback)    except ImportError:        pass    return res# ??? ?? ????????????????????????????????????????????????def _parse_directory(dir_text: str, expected_count: int) -> list:    chapters = []    for line in dir_text.strip().split('\n'):        line = line.strip()        if not line:            continue        m = re.match(r'?(\d+)?[?:]?\s*(.+?)(?:[?\-?]\s*(.+))?$', line)        if m:            chapters.append({"num": int(m.group(1)), "title": m.group(2).strip(),                             "desc": m.group(3).strip() if m.group(3) else ""})        else:            m2 = re.match(r'(\d+)[.??\s]+(.+)', line)            if m2:                rest = m2.group(2).strip()                parts = re.split(r'[??\-]', rest, 1)                chapters.append({"num": int(m2.group(1)),                                 "title": parts[0].strip(),                                 "desc": parts[1].strip() if len(parts) > 1 else ""})    chapters.sort(key=lambda x: x["num"])    if not chapters:        chapters = [{"num": i, "title": f"?{i}?", "desc": ""}                    for i in range(1, expected_count + 1)]    return chapters# ???????????????????????????????????????????????????????????# VectorContext ? ?????????# ???????????????????????????????????????????????????????????class VectorContext:    """    ???????????    ?? sentence-transformers ? embedding + ????????    ??? Chroma/FAISS?? numpy ???    pip install sentence-transformers numpy    """    def __init__(self, model_name: str = "paraphrase-multilingual-MiniLM-L12-v2"):        try:            from sentence_transformers import SentenceTransformer            import numpy as np            self._numpy = np            self._model = SentenceTransformer(model_name)            self._chapters = []  # [{num, title, text, vec}]        except ImportError:            self._model = None            import logging            logging.getLogger('novel_factory').warning(                "sentence-transformers not installed, falling back to text summary")    def add_chapter(self, chapter_num: int, title: str, text: str):        """???????"""        if not self._model:            return        vec = self._model.encode(text[:2000])  # ???? 2000 ?        self._chapters.append({            "num": chapter_num,            "title": title,            "text": text[:1000],  # ????            "vec": vec        })    def search(self, query: str, n: int = 3) -> str:        """?????? n ??????"""        if not self._model or not self._chapters:            return ""        q_vec = self._model.encode(query)        scores = []        for ch in self._chapters:            sim = float(self._numpy.dot(q_vec, ch["vec"]) /                       (self._numpy.linalg.norm(q_vec) * self._numpy.linalg.norm(ch["vec"])))            scores.append((sim, ch))        scores.sort(reverse=True)        parts = []        for sim, ch in scores[:n]:            parts.append(f"?{ch['num']}??{ch['title']}??{ch['text']}")        return "\n\n".join(parts)# ???????????????????????????????????????????????????????????# validate_chapter ? ??/???/????# ???????????????????????????????????????????????????????????def validate_chapter(content: str, chapter_num: int, target_words: int,                     book_dir: str) -> dict:    """    ??????????    1. ????? ?30%    2. ?????????? "??" "??" "??" "??" "??" ?    3. ????? 300 ??????/??    """    issues = []    # ????    wc = count_words(content)    min_w = int(target_words * 0.7)    max_w = int(target_words * 1.3)    if wc < min_w:        issues.append(f"????: {wc}/{target_words} (?? {min_w})")    elif wc > max_w:        issues.append(f"????: {wc}/{target_words} (?? {max_w})")    # ?????    banned = ["??", "??", "??", "??", "??", "??", "??"]    found_banned = [w for w in banned if w in content]    if found_banned:        issues.append(f"?????: {', '.join(found_banned)}")    # ??????? 300 ??    if len(content) > 300:        last_300 = content[-300:]    else:        last_300 = content    hook_kw = ["?", "?", "??", "??", "??", "??",               "????", "??", "??", "??", "???", "??"]    if not any(kw in last_300 for kw in hook_kw):        issues.append("????????")    return {"pass": len(issues) == 0, "issues": issues}# ???????????????????????????????????????????????????????????# _route_model ? ?????# ???????????????????????????????????????????????????????????def _route_model(task_type: str, config: dict) -> dict:    """    ???????    - use_local=true ? ?????????/???    - use_local=false ? ?????    - ?? API key ?? ? ???????    """    use_local = config.get("use_local", False)    has_cloud_key = bool(config.get("llm", {}).get("api_key", ""))    # ?????????????? API key    if use_local or not has_cloud_key:        return {            "provider": "ollama",            "model": config.get("local_llm", {}).get("model_name", "qwen2.5:7b"),            "api_key": config.get("local_llm", {}).get("api_key", "ollama"),            "base_url": config.get("local_llm", {}).get("base_url", "http://localhost:11434/v1"),            "use_local": True,        }    # ????    return {        "provider": config["llm"]["provider"],        "model": config["llm"]["model_name"],        "api_key": config["llm"]["api_key"],        "base_url": config["llm"]["base_url"],        "use_local": False,    }# ???????????????????????????????????????????????????????????# ?? ? ??????????# ???????????????????????????????????????????????????????????def continue_novel(book_dir: str, additional_chapters: int = 10,                   log_callback=None, stream_callback=None,                   stop_flag=None, progress_callback=None) -> dict:    """    ?????????????    ???????/??/??????????????    """    from core import load_config, read_file, count_words, write_file    # ?? checkpoint ???????    cp = load_checkpoint(book_dir)    if cp:        topic = cp.get("topic", ')        genre = cp.get("genre", ')        target_words = cp.get("target_words", 3000)        total_planned = cp.get("total_chapters", 0)    else:        cfg = load_config()        topic = cfg["novel"]["topic"]        genre = cfg["novel"]["genre"]        target_words = cfg["novel"]["words_per_chapter"]        total_planned = 0    # ??????    novel_setting = read_file(os.path.join(book_dir, "??.md"))    directory_text = read_file(os.path.join(book_dir, "??.md"))    summary = read_file(os.path.join(book_dir, "????.txt"))    if not summary:        summary = f"{topic}????????\n"    # ???????    ch_dir = os.path.join(book_dir, "??")    existing = sorted([f for f in os.listdir(ch_dir) if f.endswith('.md')]) if os.path.exists(ch_dir) else []    num_existing = 0    for fname in existing:        m = re.match(r'?(\d+)?', fname)        if m:            num_existing = max(num_existing, int(m.group(1)))    start_chapter = num_existing + 1    end_chapter = num_existing + additional_chapters    if log_callback:        log_callback(f"\n[??] ??{start_chapter}?????? {additional_chapters} ? (?{start_chapter}-{end_chapter}?)")    start_time = time.time()    total_generated = 0    chapters_done = 0    # ?????????    try:        _vector_ctx = VectorContext()        # ??????        for fname in existing[-5:]:  # ??5?            content = read_file(os.path.join(ch_dir, fname))            m = re.match(r'?(\d+)?_(.+)\.md', fname)            if m and content:                _vector_ctx.add_chapter(int(m.group(1)), m.group(2), content[:2000])    except Exception:        _vector_ctx = None    # ??    for ch_num in range(start_chapter, start_chapter + additional_chapters):        if stop_flag and stop_flag.is_set():            break        if _vector_ctx and chapters_done > 0:            retrieved = _vector_ctx.search(f"?{ch_num}?", n=3)            if retrieved:                current_summary = f"{summary}\n\n## ????\n{retrieved}"            else:                current_summary = summary        else:            current_summary = summary        if log_callback:            log_callback(f"  [{ch_num-start_chapter+1}/{additional_chapters}] ?{ch_num}? ???...")        if progress_callback:            progress_callback("chapter_start", {                "chapter_num": ch_num, "title": f"???{ch_num}?",                "total": additional_chapters})        # ?????????        ch_title = f"???{ch_num}?"        prompt = CHAPTER_GENERATION.format(            chapter_num=ch_num, novel_setting=novel_setting,            directory=directory_text, summary_text=current_summary,            chapter_title=ch_title, chapter_desc="?????????",            target_words=target_words)        if stream_callback:            content = llm_invoke(prompt,                system_msg="?????????????????????????????",                stream_callback=stream_callback, stop_flag=stop_flag)        else:            content = llm_invoke_ada(prompt,                system_msg="?????????????????????????????")        if not content or content.startswith("[??]"):            if log_callback:                log_callback(f"  ? ?{ch_num}?????")            continue        # ? AI ?        from deslop import rule_based_deslop        cleaned, _ = rule_based_deslop(content)        ch_file = os.path.join(ch_dir, f"?{ch_num:03d}?_{ch_title}.md")        write_file(ch_file, cleaned)        wc = count_words(cleaned)        chapters_done += 1        total_generated += wc        if log_callback:            log_callback(f"  ? {wc} ?")        if progress_callback:            progress_callback("chapter_done", {                "chapter_num": ch_num, "title": ch_title,                "words": wc, "path": ch_file, "elapsed": round(time.time()-start_time,1)})        # ????        new_summary = update_summary(ch_num, ch_title, cleaned, summary, book_dir, log_callback)        if new_summary:            summary = new_summary        # ??        if _vector_ctx:            _vector_ctx.add_chapter(ch_num, ch_title, cleaned)        # ???        save_checkpoint(book_dir, chapters_done, summary,                              total_chapters=num_chapters, topic=topic,                              genre=genre, target_words=target_words)    elapsed = time.time() - start_time    res = {        "status": "??" if chapters_done == additional_chapters else "????",        "book_dir": book_dir, "chapters_added": chapters_done,        "total_words": total_generated,        "elapsed_seconds": round(elapsed, 1),    }    if log_callback:        log_callback(f"\n[??] ?? {chapters_done}/{additional_chapters} ? | {total_generated:,} ? | {elapsed:.0f}s")    return resfixed compress_summary
